#include <stdio.h>

int main() {
    int n, i, qt, count = 0, temp, sq = 0;
    int bt[10], wt[10], tat[10], rem_bt[10];
    float awt = 0, atat = 0;

    printf("Enter number of processes: ");
    scanf("%d", &n);

    printf("Enter burst time:\n");
    for (i = 0; i < n; i++) {
        scanf("%d", &bt[i]);
        rem_bt[i] = bt[i];
    }

    printf("Enter time quantum: ");
    scanf("%d", &qt);

    while (1) {
        for (i = 0, count = 0; i < n; i++) {
            temp = qt;

            if (rem_bt[i] == 0) {
                count++;
                continue;
            }

            if (rem_bt[i] > qt)
                rem_bt[i] -= qt;
            else {
                temp = rem_bt[i];
                rem_bt[i] = 0;
            }

            sq += temp;
            tat[i] = sq;
        }

        if (n == count)
            break;
    }

    printf("\nProcess\tBT\tTAT\tWT\n");
    for (i = 0; i < n; i++) {
        wt[i] = tat[i] - bt[i];
        awt += wt[i];
        atat += tat[i];
        printf("P%d\t%d\t%d\t%d\n", i + 1, bt[i], tat[i], wt[i]);
    }

    printf("Average WT = %f\n", awt / n);
    printf("Average TAT = %f\n", atat / n);

    return 0;
}

