#include <semaphore.h>
#include <unistd.h>

#define BUFFER_SIZE 5

int buffer[BUFFER_SIZE];
int in = 0, out = 0;
sem_t mutex, full, empty;

void* producer(void* arg) {
    int item;
    for (int i = 0; i < 10; i++) {
        item = i;  
        sem_wait(&empty);
        sem_wait(&mutex);

        buffer[in] = item;
        printf("Producer produced: %d\n", item);
        in = (in + 1) % BUFFER_SIZE;

        sem_post(&mutex);
        sem_post(&full);
        sleep(1);
    }
    return NULL;
}

void* consumer(void* arg) {
    for (int i = 0; i < 10; i++) {
        sem_wait(&full);
        sem_wait(&mutex);

        int item = buffer[out];
        printf("Consumer consumed: %d\n", item);
        out = (out + 1) % BUFFER_SIZE;

        sem_post(&mutex);
        sem_post(&empty);
        sleep(2);
    }
    return NULL;
}

int main() {
    pthread_t p1, c1;

    sem_init(&mutex, 0, 1);
    sem_init(&full, 0, 0);
    sem_init(&empty, 0, BUFFER_SIZE);

    pthread_create(&p1, NULL, producer, NULL);
    pthread_create(&c1, NULL, consumer, NULL);

    pthread_join(p1, NULL);
    pthread_join(c1, NULL);

    sem_destroy(&mutex);
    sem_destroy(&full);
    sem_destroy(&empty);

    return 0;
}

#include <stdio.h>

int main() {
    
    
    int p, c, count = 0, i, j, a[5][3], max[5][3], need[5][3], safe[5], available[3], done[5], terminate = 0;

    printf("Enter the number of process and resources");
    scanf("%d %d", &p, &c);

    
    printf("enter allocation of resource of all process %dx%d matrix", p, c);
    for (i = 0; i < p; i++) {
        for (j = 0; j < c; j++) {
            scanf("%d", &a[i][j]);
        }
    }

    printf("enter the max resource process required %dx%d matrix", p, c);
    for (i = 0; i < p; i++) {
        for (j = 0; j < c; j++) {
            scanf("%d", &max[i][j]);
        }
    }

    printf("enter the available resource");
    for (i = 0; i < c; i++) {
        scanf("%d", &available[i]);
    }

    printf("\n need resources matrix are\n");
    for (i = 0; i < p; i++) {
        for (j = 0; j < c; j++) {
            need[i][j] = max[i][j] - a[i][j];
            printf("%d\t", need[i][j]);
        }
        printf("\n");
    }

    
    for (i = 0; i < p; i++) {
        done[i] = 0;
    }

    while (count < p) {
        for (i = 0; i < p; i++) {
            if (done[i] == 0) {
                for (j = 0; j < c; j++) {
                    if (need[i][j] > available[j])
                        break;
                }

                
                if (j == c) {
                    safe[count] = i;
                    done[i] = 1;

                    
                    for (j = 0; j < c; j++) {
                        available[j] += a[i][j];
                    }

                    count++;
                    terminate = 0;
                } else {
                    terminate++;
                }
            }
        }

        if (terminate == (p - 1)) {
            printf("safe sequence does not exist");
            break;
        }
    }

    if (terminate != (p - 1)) {
        printf("\n available resource after completion\n");
        for (i = 0; i < c; i++) {
            printf("%d\t", available[i]);
        }

        printf("\n safe sequence are\n");
        for (i = 0; i < p; i++) {
            printf("p%d\t", safe[i]);
        }
    }

    return 0;
}

#include <stdio.h>

void firstFit(int blocks[], int m, int processes[], int n) {
    int allocation[n];
    for (int i = 0; i < n; i++) allocation[i] = -1;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (blocks[j] >= processes[i]) {
                allocation[i] = j;
                blocks[j] -= processes[i];
                break;
            }
        }
    }

    printf("\nFirst Fit:\n");
    for (int i = 0; i < n; i++) {
        if (allocation[i] != -1)
            printf("P%d -> B%d\n", i + 1, allocation[i] + 1);
        else
            printf("P%d -> Not Allocated\n", i + 1);
    }
}

void bestFit(int blocks[], int m, int processes[], int n) {
    int allocation[n];
    for (int i = 0; i < n; i++) allocation[i] = -1;

    for (int i = 0; i < n; i++) {
        int best = -1;
        for (int j = 0; j < m; j++) {
            if (blocks[j] >= processes[i]) {
                if (best == -1 || blocks[j] < blocks[best])
                    best = j;
            }
        }
        if (best != -1) {
            allocation[i] = best;
            blocks[best] -= processes[i];
        }
    }

    printf("\nBest Fit:\n");
    for (int i = 0; i < n; i++) {
        if (allocation[i] != -1)
            printf("P%d -> B%d\n", i + 1, allocation[i] + 1);
        else
            printf("P%d -> Not Allocated\n", i + 1);
    }
}

void worstFit(int blocks[], int m, int processes[], int n) {
    int allocation[n];
    for (int i = 0; i < n; i++) allocation[i] = -1;

    for (int i = 0; i < n; i++) {
        int worst = -1;
        for (int j = 0; j < m; j++) {
            if (blocks[j] >= processes[i]) {
                if (worst == -1 || blocks[j] > blocks[worst])
                    worst = j;
            }
        }
        if (worst != -1) {
            allocation[i] = worst;
            blocks[worst] -= processes[i];
        }
    }

    printf("\nWorst Fit:\n");
    for (int i = 0; i < n; i++) {
        if (allocation[i] != -1)
            printf("P%d -> B%d\n", i + 1, allocation[i] + 1);
        else
            printf("P%d -> Not Allocated\n", i + 1);
    }
}

int main() {
    int blocks[] = {100, 500, 200, 300, 600};
    int processes[] = {212, 417, 112, 426};
    int m = 5, n = 4;
    int b1[5], b2[5], b3[5];

    for (int i = 0; i < m; i++) {
        b1[i] = blocks[i];
        b2[i] = blocks[i];
        b3[i] = blocks[i];
