#include <stdio.h>

int main() {
    int pages[50], frames[10], time[10];
    int n, f, i, j, k, flag, faults = 0;
    int counter = 0, pos, min;

    
    printf("Enter number of pages: ");
    scanf("%d", &n);

    
    printf("Enter page reference string:\n");
    for (i = 0; i < n; i++) {
        scanf("%d", &pages[i]);
    }

    
    printf("Enter number of frames: ");
    scanf("%d", &f);

    
    for (i = 0; i < f; i++) {
        frames[i] = -1;
        time[i] = 0;
    }

    printf("\nPage\tFrames\n");

    
    for (i = 0; i < n; i++) {
        flag = 0;

        
        for (j = 0; j < f; j++) {
            if (frames[j] == pages[i]) {
                counter++;
                time[j] = counter;   
                flag = 1;
                break;
            }
        }

        
        if (flag == 0) {
            min = time[0];
            pos = 0;

            
            for (j = 1; j < f; j++) {
                if (time[j] < min) {
                    min = time[j];
                    pos = j;
                }
            }

            
            frames[pos] = pages[i];
            counter++;
            time[pos] = counter;
            faults++;
        }

        
        printf("%d\t", pages[i]);
        for (k = 0; k < f; k++) {
            if (frames[k] != -1)
                printf("%d ", frames[k]);
            else
                printf("- ");
        }
        printf("\n");
    }

    printf("\nTotal Page Faults (LRU) = %d\n", faults);

    return 0;
}
